  1	import * as React from 'react';
  2	import { KialiAppState } from '../../store/Store';
  3	import { activeClustersSelector, activeNamespacesSelector, namespacesPerClusterSelector } from '../../store/Selectors';
  4	import { connect } from 'react-redux';
  5	import { Namespace } from '../../types/Namespace';
  6	import { MeshCluster } from '../../types/Mesh';
  7	import {
  8	  ActionGroup,
  9	  Button,
 10	  ButtonVariant,
 11	  Form,
 12	  FormGroup,
 13	  FormHelperText,
 14	  HelperText,
 15	  HelperTextItem,
 16	  TextInput
 17	} from '@patternfly/react-core';
 18	import { RenderContent } from '../../components/Nav/Page';
 19	import { kialiStyle } from 'styles/StyleUtils';
 20	import { GatewayForm, GatewayState, initGateway, isGatewayStateValid } from './GatewayForm';
 21	import { K8sGatewayForm, K8sGatewayState, initK8sGateway, isK8sGatewayStateValid } from './K8sGatewayForm';
 22	import {
 23	  K8sReferenceGrantForm,
 24	  K8sReferenceGrantState,
 25	  initK8sReferenceGrant,
 26	  isK8sReferenceGrantStateValid
 27	} from './K8sReferenceGrantForm';
 28	import { SidecarForm, initSidecar, isSidecarStateValid, SidecarState } from './SidecarForm';
 29	import { Paths, serverConfig } from '../../config';
 30	import { KialiIcon } from '../../config/KialiIcon';
 31	import { PromisesRegistry } from '../../utils/CancelablePromises';
 32	import * as API from '../../services/Api';
 33	import { IstioPermissions } from '../../types/IstioConfigDetails';
 34	import * as AlertUtils from '../../utils/AlertUtils';
 35	import { router } from '../../app/History';
 36	import {
 37	  buildAuthorizationPolicy,
 38	  buildGateway,
 39	  buildK8sGateway,
 40	  buildK8sReferenceGrant,
 41	  buildPeerAuthentication,
 42	  buildRequestAuthentication,
 43	  buildServiceEntry,
 44	  buildSidecar
 45	} from '../../components/IstioWizards/WizardActions';
 46	import { MessageType } from '../../types/MessageCenter';
 47	import {
 48	  AuthorizationPolicyForm,
 49	  AuthorizationPolicyState,
 50	  initAuthorizationPolicy,
 51	  isAuthorizationPolicyStateValid
 52	} from './AuthorizationPolicyForm';
 53	import {
 54	  PeerAuthenticationForm,
 55	  initPeerAuthentication,
 56	  isPeerAuthenticationStateValid,
 57	  PeerAuthenticationState
 58	} from './PeerAuthenticationForm';
 59	import {
 60	  RequestAuthenticationForm,
 61	  initRequestAuthentication,
 62	  isRequestAuthenticationStateValid,
 63	  RequestAuthenticationState
 64	} from './RequestAuthenticationForm';
 65	import { isValidK8SName } from '../../helpers/ValidationHelpers';
 66	import { DefaultSecondaryMasthead } from '../../components/DefaultSecondaryMasthead/DefaultSecondaryMasthead';
 67	import { ServiceEntryForm, initServiceEntry, isServiceEntryValid, ServiceEntryState } from './ServiceEntryForm';
 68	import { ConfigPreviewItem, IstioConfigPreview } from 'components/IstioConfigPreview/IstioConfigPreview';
 69	import { isValid } from 'utils/Common';
 70	import { ClusterDropdown } from './ClusterDropdown';
 71	import { NamespaceDropdown } from '../../components/Dropdown/NamespaceDropdown';
 72	import { Labels } from '../../components/Label/Labels';
 73	import { WizardLabels } from '../../components/IstioWizards/WizardLabels';
 74	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 75	import { dicTypeToGVK, gvkType } from '../../types/IstioConfigList';
 76	import { getGVKTypeString } from '../../utils/IstioConfigUtils';
 77	import { GroupVersionKind } from '../../types/IstioObjects';
 78	import { useKialiTranslation } from 'utils/I18nUtils';
 79	import { usePreviousValue } from 'utils/ReactUtils';
 80	import { istioNamespaces } from 'config/ServerConfig';
 81	
 82	type ReduxProps = {
 83	  activeClusters: MeshCluster[];
 84	  activeNamespaces: Namespace[];
 85	  kiosk: string;
 86	  namespacesPerCluster?: Map<string, string[]>;
 87	};
 88	
 89	type Props = ReduxProps & {
 90	  objectGVK: GroupVersionKind;
 91	};
 92	
 93	const formPadding = kialiStyle({ padding: '2rem 1.25rem' });
 94	
 95	const editIcon = kialiStyle({
 96	  marginLeft: '0.25rem',
 97	  marginBottom: '0.20rem'
 98	});
 99	
100	const editButton = kialiStyle({
101	  marginLeft: '0.5rem',
102	  display: 'flex',
103	  alignItems: 'center'
104	});
105	
106	const editStyle = kialiStyle({
107	  display: 'flex',
108	  paddingTop: '0.25rem'
109	});
110	
111	// Used in the Istio Config list Actions
112	export const NEW_ISTIO_RESOURCE = [
113	  { value: dicTypeToGVK[gvkType.AuthorizationPolicy], disabled: false },
114	  { value: dicTypeToGVK[gvkType.Gateway], disabled: false },
115	  { value: dicTypeToGVK[gvkType.K8sGateway], disabled: false },
116	  { value: dicTypeToGVK[gvkType.K8sReferenceGrant], disabled: false },
117	  { value: dicTypeToGVK[gvkType.PeerAuthentication], disabled: false },
118	  { value: dicTypeToGVK[gvkType.RequestAuthentication], disabled: false },
119	  { value: dicTypeToGVK[gvkType.ServiceEntry], disabled: false },
120	  { value: dicTypeToGVK[gvkType.Sidecar], disabled: false }
121	];
122	
123	const IstioConfigNewPageComponent: React.FC<Props> = (props: Props) => {
124	  const [annotations, setAnnotations] = React.useState<{ [key: string]: string }>({});
125	  const [authorizationPolicy, setAuthorizationPolicy] = React.useState<AuthorizationPolicyState>(
126	    initAuthorizationPolicy()
127	  );
128	  const [gateway, setGateway] = React.useState<GatewayState>(initGateway());
129	  const [istioPermissions, setIstioPermissions] = React.useState<IstioPermissions>({});
130	  const [itemsPreview, setItemsPreview] = React.useState<ConfigPreviewItem[]>([]);
131	  const [k8sGateway, setK8sGateway] = React.useState<K8sGatewayState>(initK8sGateway());
132	  const [k8sReferenceGrant, setK8sReferenceGrant] = React.useState<K8sReferenceGrantState>(initK8sReferenceGrant());
133	  const [labels, setLabels] = React.useState<{ [key: string]: string }>({});
134	  const [name, setName] = React.useState<string>('');
135	  const [peerAuthentication, setPeerAuthentication] = React.useState<PeerAuthenticationState>(initPeerAuthentication());
136	  const [requestAuthentication, setRequestAuthentication] = React.useState<RequestAuthenticationState>(
137	    initRequestAuthentication()
138	  );
139	  const [serviceEntry, setServiceEntry] = React.useState<ServiceEntryState>(initServiceEntry());
140	  const [showAnnotationsWizard, setShowAnnotationsWizard] = React.useState<boolean>(false);
141	  const [showLabelsWizard, setShowLabelsWizard] = React.useState<boolean>(false);
142	  const [showPreview, setShowPreview] = React.useState<boolean>(false);
143	  const [sidecar, setSidecar] = React.useState<SidecarState>(initSidecar(`${istioNamespaces()[0]}/*`));
144	
145	  const { t } = useKialiTranslation();
146	
147	  const promises = React.useRef<PromisesRegistry>();
148	
149	  // Promises initialization
150	  React.useEffect(() => {
151	    promises.current = new PromisesRegistry();
152	
153	    return () => {
154	      promises.current?.cancelAll();
155	    };
156	  }, []);
157	
158	  const { activeNamespaces, activeClusters, namespacesPerCluster, objectGVK } = props;
159	
160	  const canCreateNamespace = React.useCallback(
161	    (namespace: string, permissions: IstioPermissions): boolean => {
162	      return (
163	        permissions[namespace] &&
164	        objectGVK.Kind.length > 0 &&
165	        permissions[namespace][getGVKTypeString(objectGVK)].create
166	      );
167	    },
168	    [objectGVK]
169	  );
170	
171	  const isNamespaceInCluster = React.useCallback(
172	    (namespace: string, cluster: string): boolean => {
173	      return (
174	        namespacesPerCluster !== undefined &&
175	        namespacesPerCluster.has(cluster) &&
176	        namespacesPerCluster.get(cluster)!.includes(namespace)
177	      );
178	    },
179	    [namespacesPerCluster]
180	  );
181	
182	  const fetchPermissionsForCluster = React.useCallback(
183	    (cluster?: string): void => {
184	      if (activeNamespaces.length > 0) {
185	        promises.current
186	          ?.register(
187	            `permissions${cluster}`,
188	            API.getIstioPermissions(
189	              activeNamespaces.map(n => n.name),
190	              cluster
191	            )
192	          )
193	          .then(permResponse => {
194	            setIstioPermissions(permResponse.data);
195	
196	            activeNamespaces.forEach(ns => {
197	              if (!canCreateNamespace(ns.name, permResponse.data)) {
198	                AlertUtils.addWarning(
199	                  `${t('User does not have permission to create Istio Config on namespace: {{namespace}}', {
200	                    namespace: ns.name
201	                  })}${cluster ? t(' in cluster {{clusterName}}', { clusterName: cluster }) : ''}`
202	                );
203	              }
204	
205	              if (cluster && !isNamespaceInCluster(ns.name, cluster)) {
206	                AlertUtils.addInfo(
207	                  t('Namespace: {{namespace}} is not found in cluster {{clusterName}}', {
208	                    namespace: ns.name,
209	                    clusterName: cluster
210	                  })
211	                );
212	              }
213	            });
214	          })
215	          .catch(error => {
216	            // Canceled errors are expected on this query when page is unmounted
217	            if (!error.isCanceled) {
218	              AlertUtils.addError(t('Could not fetch Permissions.'), error);
219	            }
220	          });
221	      }
222	    },
223	    [activeNamespaces, promises, t, isNamespaceInCluster, canCreateNamespace]
224	  );
225	
226	  const fetchPermissions = React.useCallback(() => {
227	    if (activeClusters.length > 0) {
228	      activeClusters.forEach(cluster => {
229	        fetchPermissionsForCluster(cluster.name);
230	      });
231	    } else {
232	      fetchPermissionsForCluster();
233	    }
234	  }, [activeClusters, fetchPermissionsForCluster]);
235	
236	  const prevActiveClusters = usePreviousValue(activeClusters);
237	  const prevActiveNamespaces = usePreviousValue(activeNamespaces);
238	
239	  React.useEffect(() => {
240	    // Fetch permissions if the activeClusters or activeNamespaces change
241	    if (prevActiveClusters !== activeClusters || prevActiveNamespaces !== activeNamespaces) {
242	      fetchPermissions();
243	    }
244	  }, [prevActiveClusters, activeClusters, prevActiveNamespaces, activeNamespaces, fetchPermissions]);
245	
246	  const onNameChange = (_event: React.FormEvent, value: string): void => {
247	    setName(value);
248	  };
249	
250	  const onLabelsWizardToggle = (value: boolean): void => {
251	    setShowLabelsWizard(value);
252	  };
253	
254	  const onAddLabels = (value: { [key: string]: string }): void => {
255	    setLabels(value);
256	    setShowLabelsWizard(false);
257	  };
258	
259	  const onAnnotationsWizardToggle = (value: boolean): void => {
260	    setShowAnnotationsWizard(value);
261	  };
262	
263	  const onAddAnnotations = (value: { [key: string]: string }): void => {
264	    setAnnotations(value);
265	    setShowAnnotationsWizard(false);
266	  };
267	
268	  const onIstioResourceCreate = (): void => {
269	    if (props.activeClusters.length > 0) {
270	      props.activeClusters.forEach(cluster => {
271	        onIstioResourceCreateForCluster(cluster.name);
272	      });
273	    } else {
274	      onIstioResourceCreateForCluster();
275	    }
276	  };
277	
278	  const onIstioResourceCreateForCluster = async (cluster?: string): Promise<void> => {
279	    const jsonIstioObjects: { json: string; namespace: string }[] = itemsPreview.map(item => ({
280	      json: JSON.stringify(item.items[0]),
281	      namespace: item.items[0].metadata.namespace ?? ''
282	    }));
283	
284	    let err = 0;
285	    await Promise.all(
286	      jsonIstioObjects
287	        .map(o => API.createIstioConfigDetail(o.namespace, props.objectGVK, o.json, cluster))
288	        .map(p =>
289	          p.catch(error => {
290	            // ignore 404 errors besides no CRD found ones
291	            if (
292	              error.response.status !== 404 ||
293	              API.getErrorString(error).includes('the server could not find the requested resource')
294	            ) {
295	              AlertUtils.addError(
296	                `${t('Could not create Istio {{type}} objects', { type: getGVKTypeString(props.objectGVK) })}${
297	                  cluster ? t(' in cluster {{clusterName}}', { clusterName: cluster }) : ''
298	                }`,
299	                error
300	              );
301	              err++;
302	            }
303	          })
304	        )
305	    ).then(results => {
306	      if (results.filter(value => value !== undefined).length > 0) {
307	        AlertUtils.add(
308	          `${t('Istio {{type}} created', { type: getGVKTypeString(props.objectGVK) })}${
309	            cluster ? t(' in cluster {{clusterName}}', { clusterName: cluster }) : ''
310	          }`,
311	          'default',
312	          MessageType.SUCCESS
313	        );
314	      }
315	    });
316	
317	    if (err === 0) {
318	      backToList();
319	    }
320	  };
321	
322	  const openPreview = (): void => {
323	    const items: ConfigPreviewItem[] = [];
324	    props.activeNamespaces.forEach(ns => {
325	      switch (getGVKTypeString(props.objectGVK)) {
326	        case getGVKTypeString(gvkType.AuthorizationPolicy):
327	          items.push({
328	            title: t('Authorization Policy'),
329	            objectGVK: props.objectGVK,
330	            items: [buildAuthorizationPolicy(annotations, labels, name, ns.name, authorizationPolicy)]
331	          });
332	          break;
333	        case getGVKTypeString(gvkType.Gateway):
334	          items.push({
335	            title: t('Gateway'),
336	            objectGVK: props.objectGVK,
337	            items: [buildGateway(annotations, labels, name, ns.name, gateway)]
338	          });
339	          break;
340	        case getGVKTypeString(gvkType.K8sGateway):
341	          items.push({
342	            title: t('K8s Gateway'),
343	            objectGVK: props.objectGVK,
344	            items: [buildK8sGateway(annotations, labels, name, ns.name, k8sGateway)]
345	          });
346	          break;
347	        case getGVKTypeString(gvkType.K8sReferenceGrant):
348	          items.push({
349	            title: t('K8s Reference Grant'),
350	            objectGVK: props.objectGVK,
351	            items: [buildK8sReferenceGrant(annotations, labels, name, ns.name, k8sReferenceGrant)]
352	          });
353	          break;
354	        case getGVKTypeString(gvkType.PeerAuthentication):
355	          items.push({
356	            title: t('Peer Authentication'),
357	            objectGVK: props.objectGVK,
358	            items: [buildPeerAuthentication(annotations, labels, name, ns.name, peerAuthentication)]
359	          });
360	          break;
361	        case getGVKTypeString(gvkType.RequestAuthentication):
362	          items.push({
363	            title: t('Request Authentication'),
364	            objectGVK: props.objectGVK,
365	            items: [buildRequestAuthentication(annotations, labels, name, ns.name, requestAuthentication)]
366	          });
367	          break;
368	        case getGVKTypeString(gvkType.ServiceEntry):
369	          items.push({
370	            title: t('Service Entry'),
371	            objectGVK: props.objectGVK,
372	            items: [buildServiceEntry(annotations, labels, name, ns.name, serviceEntry)]
373	          });
374	          break;
375	        case getGVKTypeString(gvkType.Sidecar):
376	          items.push({
377	            title: t('Sidecar'),
378	            objectGVK: props.objectGVK,
379	            items: [buildSidecar(annotations, labels, name, ns.name, sidecar)]
380	          });
381	          break;
382	      }
383	    });
384	    setItemsPreview(items);
385	    setShowPreview(true);
386	    //onIstioResourceCreate()
387	  };
388	
389	  const backToList = (): void => {
390	    // Back to list page
391	    const backUrl = `/${Paths.ISTIO}?namespaces=${props.activeNamespaces.map(n => n.name).join(',')}`;
392	    if (isParentKiosk(props.kiosk)) {
393	      kioskContextMenuAction(backUrl);
394	    } else {
395	      router.navigate(backUrl);
396	    }
397	  };
398	
399	  const isIstioFormValid = (): boolean => {
400	    switch (getGVKTypeString(props.objectGVK)) {
401	      case getGVKTypeString(gvkType.AuthorizationPolicy):
402	        return isAuthorizationPolicyStateValid(authorizationPolicy);
403	      case getGVKTypeString(gvkType.Gateway):
404	        return isGatewayStateValid(gateway);
405	      case getGVKTypeString(gvkType.K8sGateway):
406	        return isK8sGatewayStateValid(k8sGateway);
407	      case getGVKTypeString(gvkType.K8sReferenceGrant):
408	        return isK8sReferenceGrantStateValid(k8sReferenceGrant);
409	      case getGVKTypeString(gvkType.PeerAuthentication):
410	        return isPeerAuthenticationStateValid(peerAuthentication);
411	      case getGVKTypeString(gvkType.RequestAuthentication):
412	        return isRequestAuthenticationStateValid(requestAuthentication);
413	      case getGVKTypeString(gvkType.ServiceEntry):
414	        return isServiceEntryValid(serviceEntry);
415	      case getGVKTypeString(gvkType.Sidecar):
416	        return isSidecarStateValid(sidecar);
417	      default:
418	        return false;
419	    }
420	  };
421	
422	  const onChangeAuthorizationPolicy = (authorizationPolicyValue: AuthorizationPolicyState): void => {
423	    const newAuthorizationPolicy = { ...authorizationPolicy };
424	    Object.keys(newAuthorizationPolicy).forEach(key => (newAuthorizationPolicy[key] = authorizationPolicyValue[key]));
425	
426	    setAuthorizationPolicy(newAuthorizationPolicy);
427	  };
428	
429	  const onChangeGateway = (gatewayValue: GatewayState): void => {
430	    const newGateway = { ...gateway };
431	    Object.keys(newGateway).forEach(key => (newGateway[key] = gatewayValue[key]));
432	
433	    setGateway(newGateway);
434	  };
435	
436	  const onChangeK8sGateway = (k8sGatewayValue: K8sGatewayState): void => {
437	    const newK8sGateway = { ...k8sGateway };
438	    Object.keys(newK8sGateway).forEach(key => (newK8sGateway[key] = k8sGatewayValue[key]));
439	
440	    setK8sGateway(newK8sGateway);
441	  };
442	
443	  const onChangeK8sReferenceGrant = (k8sReferenceGrantValue: K8sReferenceGrantState): void => {
444	    const newK8sReferenceGrant = { ...k8sReferenceGrant };
445	    Object.keys(newK8sReferenceGrant).forEach(key => (newK8sReferenceGrant[key] = k8sReferenceGrantValue[key]));
446	
447	    setK8sReferenceGrant(newK8sReferenceGrant);
448	  };
449	
450	  const onChangePeerAuthentication = (peerAuthenticationValue: PeerAuthenticationState): void => {
451	    const newPeerAuthentication = { ...peerAuthentication };
452	    Object.keys(newPeerAuthentication).forEach(key => (newPeerAuthentication[key] = peerAuthenticationValue[key]));
453	
454	    setPeerAuthentication(newPeerAuthentication);
455	  };
456	
457	  const onChangeRequestAuthentication = (requestAuthenticationValue: RequestAuthenticationState): void => {
458	    const newRequestAuthentication = { ...requestAuthentication };
459	    Object.keys(newRequestAuthentication).forEach(
460	      key => (newRequestAuthentication[key] = requestAuthenticationValue[key])
461	    );
462	
463	    setRequestAuthentication(newRequestAuthentication);
464	  };
465	
466	  const onChangeServiceEntry = (serviceEntryValue: ServiceEntryState): void => {
467	    const newServiceEntry = { ...serviceEntry };
468	    Object.keys(newServiceEntry).forEach(key => (newServiceEntry[key] = serviceEntryValue[key]));
469	
470	    setServiceEntry(newServiceEntry);
471	  };
472	
473	  const onChangeSidecar = (sidecarValue: SidecarState): void => {
474	    const newSidecar = { ...sidecar };
475	    Object.keys(newSidecar).forEach(key => (newSidecar[key] = sidecarValue[key]));
476	
477	    setSidecar(newSidecar);
478	  };
479	
480	  const onPreviewConfirm = (items: ConfigPreviewItem[]): void => {
481	    setShowPreview(false);
482	    setItemsPreview(items);
483	
484	    onIstioResourceCreate();
485	  };
486	
487	  const canCreate = props.activeNamespaces.every(ns => canCreateNamespace(ns.name, istioPermissions));
488	  const isNameValid = isValidK8SName(name);
489	  const isNamespacesValid = props.activeNamespaces.length > 0;
490	  const isMultiCluster = Object.keys(serverConfig.clusters).length > 1;
491	  const isClustersValid = props.activeClusters.length > 0 || !isMultiCluster;
492	  const isFormValid = isNameValid && isNamespacesValid && isClustersValid && isIstioFormValid();
493	
494	  return (
495	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
496	      <div>
497	        <DefaultSecondaryMasthead showClusterSelector={false} hideNamespaceSelector={true} />
498	      </div>
499	
500	       <div style={{ flexGrow: 1, overflowY: 'auto' }}>
501	        <RenderContent>
502	          <Form className={formPadding} isHorizontal={true}>
503	            <FormGroup label={t('Namespaces')} isRequired={true} fieldId="namespaces">
504	              <NamespaceDropdown disabled={false} />
505	
506	              {!isValid(isNamespacesValid) && (
507	                <FormHelperText>
508	                  <HelperText>
509	                    <HelperTextItem>
510	                      {t('An Istio Config resource needs at least one namespace selected')}
511	                    </HelperTextItem>
512	                  </HelperText>
513	                </FormHelperText>
514	              )}
515	            </FormGroup>
516	
517	            {isMultiCluster && (
518	              <FormGroup label={t('Clusters')} isRequired={true} fieldId="clusters">
519	                <ClusterDropdown />
520	
521	                {!isValid(isClustersValid) && (
522	                  <FormHelperText>
523	                    <HelperText>
524	                      <HelperTextItem>
525	                        {t('An Istio Config resource needs at least one cluster selected')}
526	                      </HelperTextItem>
527	                    </HelperText>
528	                  </FormHelperText>
529	                )}
530	              </FormGroup>
531	            )}
532	
533	            <FormGroup label={t('Name')} isRequired={true} fieldId="name">
534	              <TextInput
535	                value={name}
536	                isRequired={true}
537	                type="text"
538	                id="name"
539	                aria-describedby={t('name')}
540	                name="name"
541	                onChange={onNameChange}
542	                validated={isValid(isNameValid)}
543	              />
544	
545	              {!isValid(isNameValid) && (
546	                <FormHelperText>
547	                  <HelperText>
548	                    <HelperTextItem>{t('A valid {{kind}} name is required', props.objectGVK.Kind)}</HelperTextItem>
549	                  </HelperText>
550	                </FormHelperText>
551	              )}
552	            </FormGroup>
553	
554	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.AuthorizationPolicy) && (
555	              <AuthorizationPolicyForm
556	                authorizationPolicy={authorizationPolicy}
557	                onChange={onChangeAuthorizationPolicy}
558	              />
559	            )}
560	
561	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.Gateway) && (
562	              <GatewayForm gateway={gateway} onChange={onChangeGateway} />
563	            )}
564	
565	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.K8sGateway) && (
566	              <K8sGatewayForm k8sGateway={k8sGateway} onChange={onChangeK8sGateway} />
567	            )}
568	
569	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.K8sReferenceGrant) && (
570	              <K8sReferenceGrantForm k8sReferenceGrant={k8sReferenceGrant} onChange={onChangeK8sReferenceGrant} />
571	            )}
572	
573	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.PeerAuthentication) && (
574	              <PeerAuthenticationForm peerAuthentication={peerAuthentication} onChange={onChangePeerAuthentication} />
575	            )}
576	
577	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.RequestAuthentication) && (
578	              <RequestAuthenticationForm
579	                requestAuthentication={requestAuthentication}
580	                onChange={onChangeRequestAuthentication}
581	              />
582	            )}
583	
584	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.ServiceEntry) && (
585	              <ServiceEntryForm serviceEntry={serviceEntry} onChange={onChangeServiceEntry} />
586	            )}
587	
588	            {getGVKTypeString(props.objectGVK) === getGVKTypeString(gvkType.Sidecar) && (
589	              <SidecarForm sidecar={sidecar} onChange={onChangeSidecar} />
590	            )}
591	
592	            <FormGroup fieldId="labels" label="Labels">
